	require.ErrorContains(t, cfg.Validate(), "metric postgresql.bgwriter.buffers.writes doesn't have an attribute invalid, valid attributes: [source]")

	cfg = DefaultMetricsConfig().PostgresqlBgwriterBuffersWrites
